import ApiService, { ResponseType } from '@/api/api';
import { getTokenByBridge } from '@/utils';

interface FileObject {
  file_name: string;
  file_size: number;
  file_type: string;
  review_status: number;
  is_expire: number;
  category_type: number;
  child_talid: string;
}

type FileDetailType = ResponseType<FileObject>;


export const getFileDetail = async (params: {
  unique_id: string;
  child_talid: string;
}): FileDetailType => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/file-transfer/file-detail', {
    ...params,
    token
  });
};

export const checkFile = async (params: {
  status: number;
  unique_id: string;
  child_talid: string;
}): ResponseType => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/file-transfer/check', {
    ...params,
    token
  });
};

// 将消息改为已读状态
export const changeMsgReadStatus = async (id: number) => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/notice/set-read', {
    id,
    type: 1,
    token
  });
};
